//! Generate `src/lib/models.generated.ts` from the Rust model registry (source of truth).
//!
//! Usage:
//!   cargo run --manifest-path src-tauri/Cargo.toml --bin gen_model_registry
//!   cargo run --manifest-path src-tauri/Cargo.toml --bin gen_model_registry -- --check
//!
//! `--check` exits non-zero if the on-disk generated file differs (CI freshness).

use std::env;
use std::fs;
use std::path::PathBuf;
use std::process;

use yabr_lib::models::static_registry;

fn main() {
    let check_only = env::args().any(|a| a == "--check");
    let out_path = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("..")
        .join("src")
        .join("lib")
        .join("models.generated.ts");

    let generated = render_typescript();

    if check_only {
        match fs::read_to_string(&out_path) {
            Ok(existing) if normalize(&existing) == normalize(&generated) => {
                eprintln!("models.generated.ts is up to date");
                process::exit(0);
            }
            Ok(_) => {
                eprintln!(
                    "error: {} is stale; run `bun run gen:models` and commit the result",
                    out_path.display()
                );
                process::exit(1);
            }
            Err(e) => {
                eprintln!("error: cannot read {}: {}", out_path.display(), e);
                process::exit(1);
            }
        }
    }

    if let Some(parent) = out_path.parent() {
        fs::create_dir_all(parent).expect("create output dir");
    }
    fs::write(&out_path, &generated).expect("write models.generated.ts");
    eprintln!("wrote {}", out_path.display());
}

fn normalize(s: &str) -> String {
    s.replace("\r\n", "\n").trim().to_string()
}

fn js_string(s: &str) -> String {
    let mut out = String::from("\"");
    for ch in s.chars() {
        match ch {
            '\\' => out.push_str("\\\\"),
            '"' => out.push_str("\\\""),
            '\n' => out.push_str("\\n"),
            '\r' => out.push_str("\\r"),
            c => out.push(c),
        }
    }
    out.push('"');
    out
}

fn render_typescript() -> String {
    let entries = static_registry();
    let mode_union = entries
        .iter()
        .map(|m| format!("\"{}\"", m.id))
        .collect::<Vec<_>>()
        .join(" | ");

    let mut body = String::new();
    body.push_str("/* eslint-disable */\n");
    body.push_str(
        "// AUTO-GENERATED by `cargo run --bin gen_model_registry` — do not edit by hand.\n",
    );
    body.push_str("// Source of truth: src-tauri/src/models.rs\n");
    body.push_str("// Regenerate: bun run gen:models\n\n");
    body.push_str(&format!("export type ModelMode = {};\n\n", mode_union));
    body.push_str(
        "export type ModelStaticMeta = {\n\
         \tid: ModelMode;\n\
         \tname: string;\n\
         \tfile: string;\n\
         \tsize_bytes: number;\n\
         \tinput_size: number;\n\
         \tmean: number[];\n\
         \tstd: number[];\n\
         \tlicense: string;\n\
         \tsource: string;\n\
         \tdownload_url: string;\n\
         \tsha256: string;\n\
         \tbundled: boolean;\n\
         };\n\n",
    );

    body.push_str("export const MODEL_REGISTRY: readonly ModelStaticMeta[] = [\n");
    for m in entries {
        let mean = m
            .mean
            .iter()
            .map(|v| format!("{}", v))
            .collect::<Vec<_>>()
            .join(", ");
        let std = m
            .std
            .iter()
            .map(|v| format!("{}", v))
            .collect::<Vec<_>>()
            .join(", ");
        body.push_str("  {\n");
        body.push_str(&format!("    id: {},\n", js_string(&m.id)));
        body.push_str(&format!("    name: {},\n", js_string(&m.name)));
        body.push_str(&format!("    file: {},\n", js_string(&m.file)));
        body.push_str(&format!("    size_bytes: {},\n", m.size_bytes));
        body.push_str(&format!("    input_size: {},\n", m.input_size));
        body.push_str(&format!("    mean: [{}],\n", mean));
        body.push_str(&format!("    std: [{}],\n", std));
        body.push_str(&format!("    license: {},\n", js_string(&m.license)));
        body.push_str(&format!("    source: {},\n", js_string(&m.source)));
        body.push_str(&format!(
            "    download_url: {},\n",
            js_string(&m.download_url)
        ));
        body.push_str(&format!("    sha256: {},\n", js_string(&m.sha256)));
        body.push_str(&format!(
            "    bundled: {},\n",
            if m.bundled { "true" } else { "false" }
        ));
        body.push_str("  },\n");
    }
    body.push_str("];\n\n");
    body.push_str(
        "export function getModelById(\n\
         \tid: ModelMode,\n\
         \tmodels: readonly ModelStaticMeta[] = MODEL_REGISTRY,\n\
         ): ModelStaticMeta | undefined {\n\
         \treturn models.find((m) => m.id === id);\n\
         }\n",
    );
    body.replace('\t', "  ")
}
